   173→            debug!("compute_regions: using polonius algorithm {:?}", algorithm);
   174→            let _prof_timer = infcx.tcx.prof.generic_activity("polonius_analysis");
   175→            Some(Box::new(Output::compute(polonius_facts, algorithm, false)))
   176→        } else {
   177→            None
   178→        }
   179→    });
