gionInferenceContext<'tcx>,\n    closure_region_requirements: &Option<ClosureRegionRequirements<'tcx>>,\n    borrow_set: &BorrowSet<'tcx>,\n    pass_where: PassWhere,\n    out: &mut dyn io::Write,\n) -> io::Result<()> {\n    match pass_where {\n        // Before the CFG, dump out the values for each region variable.\n        PassWhere::BeforeCFG => {\n            regioncx.dump_mir(tcx, out)?;\n            writeln!(out, \"|\")?;\n\n            if let Some(closure_region_requirements) = closure_region_requirements {\n                writeln!(out, \"| Free Region Constraints\")?;\n                for_each_region_constraint(tcx, closure_region_requirements, &mut |msg| {\n                    writeln!(out, \"| {msg}\")\n                })?;\n                writeln!(out, \"|\")?;\n            }\n\n            if borrow_set.len() > 0 {\n                writeln!(out, \"| Borrows\")?;\n                for (borrow_idx, borrow_data) in borrow_set.iter_enumerated() {\n                    writeln!(\n                        out,\n                        \"| {:?}: issued at {:?} in {:?}\",\n                        borrow_idx, borrow_data.reserve_location, borrow_data.region\n                    )?;\n                }\n                writeln!(out, \"|\")?;\n            }\n        }\n\n        PassWhere::BeforeLocation(_) => {}\n\n        PassWhere::AfterTerminator(_) => {}\n\n        PassWhere::BeforeBlock(_) | PassWhere::AfterLocation(_) | PassWhere::AfterCFG => {}\n    }\n    Ok(())\n}\n\n#[allow(rustc::diagnostic_outside_of_impl)]\n#[allow(rustc::untranslatable_diagnostic)]\npub(super) fn dump_annotation<'tcx, 'infcx>(\n    infcx: &'infcx BorrowckInferCtxt<'tcx>,\n    body: &Body<'tcx>,\n    regioncx: &RegionInferenceContext<'tcx>,\n    closure_region_requirements: &Option<ClosureRegionRequirements<'tcx>>,\n) {\n    let tcx = infcx.tcx;\n    let base_def_id = tcx.typeck_root_def_id(body.source.def_id());\n    if !tcx.has_attr(base_def_id, sym::rustc_regions) {\n        return;\